  ('dietitian-moex-02943', 'dietitian', 'dietitian-moex-104-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '過氧化氫（hydrogen peroxide）做為消毒劑使用時，下列敘述何者錯誤？', '["易使金屬氧化，故應避免使用於銅、鐵、鋁製器具", "pH 10～12時殺菌效果最佳，通常配成0.2～0.3%濃度之溶液使用", "與水混合稀釋時應將水加入過氧化氫中，以避免爆炸", "使用時需有個人防護措施"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:00+00:00", "source_pdf_sha1": "97ede7473e3a", "answer_pdf_sha1": "cb81b5bef8b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02944', 'dietitian', 'dietitian-moex-104-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關定位清洗法（cleaning in place）之優點，下列敘述何者錯誤？', '["不必拆卸零件", "無清洗死角", "適用於食品工廠管路內清洗", "適用於食品工廠大桶槽清洗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:00+00:00", "source_pdf_sha1": "97ede7473e3a", "answer_pdf_sha1": "cb81b5bef8b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02945', 'dietitian', 'dietitian-moex-104-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '根據「食品良好衛生規範準則」，關於餐飲業者之洗滌場所實施之有效殺菌條件，下列敘述何者錯誤？', '["煮沸殺菌法：以溫度攝氏一百度之沸水，煮沸時間五分鐘以上（毛巾、抹布等）或一分鐘以上（餐具）", "蒸汽殺菌法：以溫度攝氏一百度之蒸汽，加熱時間十分鐘以上（毛巾、抹布等）或二分鐘以上（餐具）", "熱水殺菌法：以溫度攝氏八十度以上之熱水，加熱時間二分鐘以上（餐具）", "乾熱殺菌法：以溫度攝氏一百度以上之乾熱，加熱時間三十分鐘以上（餐具）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:00+00:00", "source_pdf_sha1": "97ede7473e3a", "answer_pdf_sha1": "cb81b5bef8b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
